mapper.select:
SELECT r.*, u.real_name AS upload_user_name, c.name AS category_name
FROM teaching_resource r
LEFT JOIN sys_user u ON r.upload_user_id = u.id
LEFT JOIN resource_category c ON r.category_id = c.id


        AND r.title LIKE CONCAT('%', #{title}, '%')


        AND r.category_id = #{categoryId}


        AND r.file_type = #{fileType}


        AND r.status = #{status}


        AND r.upload_user_id = #{uploadUserId}


ORDER BY r.create_time DESC
